class Layer:
    def __init__(self, inputs, neurons):
        self.weights = np.random.rand(inputs, neurons)
        self.bias = np.zeros((1, neurons))

    def forward(self, inputs):
        self.inputs = inputs
        self.output = np.dot(inputs, self.weights) + self.bias
        return self.output

class Activation:
    def __init__(self, activation_type):
        self.activation_type = activation_type

    def forward(self, inputs):
        if self.activation_type == 'sigmoid':
            self.output = 1 / (1 + np.exp(-inputs))
        elif self.activation_type == 'relu':
            self.output = np.maximum(0, inputs)
        return self.output

    def backward(self, inputs, delta):
        if self.activation_type == 'sigmoid':
            return delta * self.output * (1 - self.output)
        elif self.activation_type == 'relu':
            return delta * (inputs > 0).astype(int)

class NeuralNetwork:
    def __init__(self, input_size, output_size, hidden_layers):
        self.layers = []
        self.activations = []
        self.input_size = input_size
        self.output_size = output_size
        prev_layer_size = input_size
        for neurons in hidden_layers:
            self.layers.append(Layer(prev_layer_size, neurons))
            self.activations.append(Activation('relu'))
            prev_layer_size = neurons
        self.layers.append(Layer(prev_layer_size, output_size))
        self.activations.append(Activation('sigmoid'))

    def forward(self, inputs):
        for i in range(len(self.layers)):
            if i == 0:
                output = self.layers[i].forward(inputs)
            else:
                output = self.layers[i].forward(self.activations[i-1].output)
            if i < len(self.layers) - 1:
                output = self.activations[i].forward(output)
        return output

    def backward(self, inputs, targets, learning_rate):
        output = self.forward(inputs)
        delta = 2 * (output - targets)
        for i in range(len(self.layers) - 1, -1, -1):
            if i < len(self.layers) - 1:
                delta = self.activations[i].backward(self.layers[i].output, delta)
            delta = np.dot(delta, self.layers[i].weights.T)
            self.layers[i].weights -= learning_rate * np.dot(self.layers[i].inputs.T, delta)
            self.layers[i].bias -= learning_rate * np.sum(delta, axis=0, keepdims=True)

    def train(self, inputs, targets, learning_rate, epochs):
        for _ in range(epochs):
            self.backward(inputs, targets, learning_rate)

    def predict(self, inputs):
        return self.forward(inputs)

