class Layer:
    def __init__(self, input_size, output_size, activation_type=None):
        self.weights = np.random.rand(input_size, output_size)
        self.bias = np.zeros((1, output_size))
        self.activation = Activation(activation_type) if activation_type else None

    def forward(self, x):
        self.input = x
        self.output = np.dot(x, self.weights) + self.bias
        if self.activation:
            self.output = self.activation.forward(self.output)
        return self.output

    def backward(self, error):
        if self.activation:
            error = error * self.activation.backward(self.output)
        self.weight_error = np.dot(self.input.T, error)
        self.bias_error = np.sum(error, axis=0, keepdims=True)
        return np.dot(error, self.weights.T)


