        for i in range(len(hidden_sizes) - 1):
            self.layers.append(Layer(hidden_sizes[i], hidden_sizes[i+1], activation_type))
        self.layers.append(Layer(hidden_sizes[-1], output_size, 'sigmoid' if output_size == 1 else None))

