class NeuralNetwork:
    def __init__(self, input_dim, output_dim, hidden_layers):
        self.input_dim = input_dim
        self.output_dim = output_dim
        self.hidden_layers = hidden_layers
        self.weights = []
        self.biases = []
        self.activations = []
        self.deltas = []
        self.outputs = []
        self.init_weights()

    def init_weights(self):
        layers = [self.input_dim] + self.hidden_layers + [self.output_dim]
        for i in range(len(layers) - 1):
            self.weights.append(np.random.rand(layers[i], layers[i + 1]))
            self.biases.append(np.zeros((1, layers[i + 1])))
            self.activations.append(np.zeros((1, layers[i + 1])))
            self.deltas.append(np.zeros((1, layers[i + 1])))
            self.outputs.append(np.zeros((1, layers[i + 1])))

    def sigmoid(self, x):
        return 1 / (1 + np.exp(-x))

    def sigmoid_derivative(self, x):
        return x * (1 - x)

    def relu(self, x):
        return np.maximum(x, 0)

    def relu_derivative(self, x):
        return np.where(x > 0, 1, 0)

    def forward_propagate(self, inputs):
        self.outputs[0] = inputs
        for i in range(len(self.weights)):
            if i < len(self.weights) - 1:
                self.activations[i] = np.dot(self.outputs[i], self.weights[i]) + self.biases[i]
                self.outputs[i + 1] = self.relu(self.activations[i])
            else:
                self.activations[i] = np.dot(self.outputs[i], self.weights[i]) + self.biases[i]
                self.outputs[i + 1] = self.sigmoid(self.activations[i])
        return self.outputs[-1]

    def backpropagate(self, inputs, targets, learning_rate):
        self.forward_propagate(inputs)
        error = targets - self.outputs[-1]
        self.deltas[-1] = error * self.sigmoid_derivative(self.outputs[-1])
        for i in range(len(self.weights) - 2, -1, -1):
            self.deltas[i] = np.dot(self.deltas[i + 1], self.weights[i + 1].T) * self.relu_derivative(self.outputs[i + 1])
        for i in range(len(self.weights)):
            self.weights[i] += learning_rate * np.dot(self.outputs[i].T, self.deltas[i])
            self.biases[i] += learning_rate * np.sum(self.deltas[i], axis=0, keepdims=True)

    def train(self, inputs, targets, learning_rate, epochs):
        for _ in range(epochs):
            for i in range(len(inputs)):
                self.backpropagate(inputs[i], targets[i], learning_rate)

    def predict(self, inputs):
        return self.forward_propagate(inputs)

